### AI Chat JS
```javascript
async function askAi(presetMsg) {
  const input = document.getElementById('ai-input');
  const msg = presetMsg || input.value.trim();
  if (!msg) return;

  if (!presetMsg) input.value = '';

  // Hide suggestions
  document.getElementById('ai-suggestions').style.display = 'none';

  // Add user message
  addAiMessage('user', msg);

  // Show typing indicator
  const typingId = addAiMessage('typing', '');

  // Disable send
  document.getElementById('ai-send').disabled = true;

  try {
    // Use the current room PIN
    const pin = currentPin || sessionStorage.getItem('dnd_pin');
    const resp = await fetch(`/dnd-api/rooms/${pin}/ai-chat`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ message: msg })
    });
    const data = await resp.json();

    // Remove typing indicator
    removeAiMessage(typingId);

    if (data.ok) {
      addAiMessage('assistant', data.response);
    } else {
      addAiMessage('error', data.error || 'Failed to get response');
    }
  } catch (e) {
    removeAiMessage(typingId);
    addAiMessage('error', 'Connection error: ' + e.message);
  }

  document.getElementById('ai-send').disabled = false;
  input.focus();
}

function addAiMessage(role, text) {
  const container = document.getElementById('ai-messages');
  const id = 'ai-msg-' + Date.now() + Math.random().toString(36).slice(2,6);
  const div = document.createElement('div');
  div.id = id;
  div.className = 'ai-msg ai-' + role;

  if (role === 'typing') {
    div.innerHTML = '<div class="typing-dots"><span></span><span></span><span></span></div>';
  } else if (role === 'error') {
    div.innerHTML = '<span class="ai-error">⚠️ ' + escapeHtml(text) + '</span>';
  } else {
    // Simple markdown: bold, italic, code, lists
    let html = escapeHtml(text)
      .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
      .replace(/\*(.+?)\*/g, '<em>$1</em>')
      .replace(/`([^`]+)`/g, '<code>$1</code>')
      .replace(/\n/g, '<br>');
    div.innerHTML = html;
  }

  container.appendChild(div);
  container.scrollTop = container.scrollHeight;
  return id;
}

function removeAiMessage(id) {
  document.getElementById(id)?.remove();
}

function clearAiChat() {
  document.getElementById('ai-messages').innerHTML = '';
  document.getElementById('ai-suggestions').style.display = 'block';
  // Also clear server-side history
  const pin = currentPin || sessionStorage.getItem('dnd_pin');
  if (pin) fetch(`/dnd-api/rooms/${pin}/ai-chat`, { method: 'DELETE' }).catch(() => {});
}

function escapeHtml(s) { return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
```

