  const loc = window.location;
  // If served from /dnd, API is at /dnd-api
  if (loc.pathname.startsWith('/dnd')) return '/dnd-api';
  // Fallback: same origin, port 3004
  return `${loc.protocol}//${loc.hostname}:3004`;
})();

const WS_URL = (() => {
  const loc = window.location;
