async function loadSessionHistory() {
  try {
    const sessions = await api('/sessions/history');
    renderSessionHistory(sessions);
  } catch (e) {
    console.error('Load session history failed:', e);
    const list = $('#session-history-list');
    if (list) list.innerHTML = '<p class="muted">Failed to load history.</p>';
  }
}

function renderSessionHistory(sessions) {
  const list = $('#session-history-list');
  if (!list) return;

  if (!sessions || sessions.length === 0) {
    list.innerHTML = '<p class="muted">No past sessions saved yet.</p>';
    return;
  }

  list.innerHTML = '';
  sessions.forEach(s => {
    const card = document.createElement('div');
    card.className = 'history-card';
    card.innerHTML = `
      <div class="history-date">${escapeHtml(s.date)}</div>
      <div class="history-meta">
        <span class="history-dm">DM: ${escapeHtml(s.dm)}</span>
        <span class="history-players">${s.players.length > 0 ? s.players.map(p => escapeHtml(p)).join(', ') : 'No players'}</span>
      </div>
      <div class="history-brief">${escapeHtml(s.briefNotes || 'No notes').slice(0, 150)}${s.briefNotes && s.briefNotes.length > 150 ? '...' : ''}</div>
    `;
    card.addEventListener('click', () => viewSessionDetail(s.filename));
    list.appendChild(card);
  });
}

async function viewSessionDetail(filename) {
  try {
    const data = await api(`/sessions/history/${encodeURIComponent(filename)}`);
    $('#session-history-title').textContent = filename.replace('.md', '');
    const content = data.content
      .replace(/^---[\s\S]*?---\n*/, '') // strip frontmatter
      .replace(/\n/g, '<br>');
    $('#session-history-content').innerHTML = `<div class="session-md-content">${content}</div>`;
    show('#session-history-modal');
  } catch (e) {
    showToast('❌ Failed to load session: ' + e.message, 'error');
  }
}

